class Meal {
    Meal(String bun, int pattyCount, String cheese,
         boolean lettuce, boolean tomato, boolean onion,
         boolean jalapeno, boolean ketchup, boolean mayo,
         boolean bbq, boolean bacon, boolean egg,
         boolean avocado, String size) {
        // 15 parameters. Most are false.
    }
}

// Customer wants: sesame bun, 1 patty, cheddar, just lettuce, ketchup only, medium
new Meal("sesame", 1, "cheddar", true, false, false,
         false, true, false, false, false, false, false, "medium");
// 9 'false' values for things they didn't even ask about!

Meal meal = new Meal();        // What IS this? An empty meal?
meal.setBun("sesame");         // Bun but no patty...
meal.setPattyCount(2);         // Bun + patties but no size...
// ... 10 more setters ...
meal.setSize("large");         // NOW it's 'done'... but who enforces this?

// Problem 1: When is it 'done'? No completion guarantee.
// Problem 2: meal.setCheese("swiss") AFTER it was 'done'.
// Problem 3: No cross-field validation.
meal.setBun("gluten-free");
meal.setBacon(true);           // Invalid combo! But who stops this?

// WITHOUT return this:
Builder b = new Meal.Builder();
b.bun("sesame");      // void -- each call is separate
b.pattyCount(2);      // void
b.cheese("cheddar");  // void
Meal m = b.build();

// WITH return this:
Meal m = new Meal.Builder()  // Builder returns itself
    .bun("sesame")           // returns Builder -> chain continues
    .pattyCount(2)           // returns Builder -> chain continues
    .cheese("cheddar")       // returns Builder -> chain continues
    .build();                // returns Meal -- chain ends

// The implementation:
public Builder cheese(String cheese) {
    this.cheese = cheese;
    return this;  // THE MAGIC LINE
}

public Meal build() {
    // Required field checks
    if (bun == null) throw new IllegalStateException("Bun is required!");
    if (size == null) throw new IllegalStateException("Size is required!");
    if (pattyCount < 1) throw new IllegalStateException("At least 1 patty!");

    // Cross-field validation
    if (bun.equals("gluten-free") && bacon)
        throw new IllegalStateException("No bacon with gluten-free bun");
    if (pattyCount > 3)
        throw new IllegalStateException("Max 3 patties");

    // Computed fields -- caller never sets price manually
    // Price is DERIVED from other choices
    return new Meal(this);
}

// In the Meal constructor:
private Meal(Builder b) {
    this.bun = b.bun;
    this.items = List.copyOf(b.items);  // defensive copy!
    this.price = calculatePrice(b);     // computed field
}

// HttpRequest, Configuration, Query — don't change after creation
public final class HttpRequest {
    private final String url;       // final — never changes
    private final String method;    // final — never changes
    private final Map<String, String> headers; // final + defensive copy

    private HttpRequest(Builder b) {
        this.url = b.url;
        this.method = b.method;
        this.headers = Map.copyOf(b.headers);
    }
    // Only GETTERS — no setters. Truly immutable.
}

// Payment, Order, Booking — have fields that change over time
public class Payment {
    private final String orderId;       // final — identity, never changes
    private final double amount;        // final — identity, never changes
    private final String method;        // final — identity, never changes

    private PaymentStatus status;       // mutable — changes through lifecycle
    private Instant processedAt;        // mutable — set later

    private Payment(Builder b) {
        this.orderId = b.orderId;
        this.amount = b.amount;
        this.method = b.method;
        this.status = PaymentStatus.CREATED;
    }

    // Setters for lifecycle fields
    public void setStatus(PaymentStatus s) { this.status = s; }
    public void setProcessedAt(Instant t)  { this.processedAt = t; }
}

class MealRecipes {
    static Meal kidsMeal() {
        return new Meal.Builder()
            .bun("small-regular")
            .pattyCount(1)
            .cheese("american")
            .sauce("ketchup")
            .size("small")
            .build();
    }

    static Meal gourmetBurger() {
        return new Meal.Builder()
            .bun("brioche")
            .pattyCount(2)
            .cheese("gruyere")
            .lettuce(true)
            .tomato(true)
            .bacon(true)
            .sauce("truffle-mayo")
            .size("large")
            .build();
    }
}

// All services use:
Meal kids = MealRecipes.kidsMeal();       // consistent everywhere
Meal gourmet = MealRecipes.gourmetBurger(); // single source of truth

// Factory picks the RIGHT builder
Notification.Builder builder = NotificationFactory.createBuilder(channel);

// Builder configures it
Notification notif = builder
    .title("Order Shipped")
    .body("Your laptop is on the way")
    .priority(Priority.HIGH)
    .build();

// Under the hood:
class NotificationFactory {
    static Notification.Builder createBuilder(String channel) {
        return switch(channel) {
            case "push"  -> new PushNotification.Builder();
            case "email" -> new EmailNotification.Builder();
            case "sms"   -> new SMSNotification.Builder();
        };
    }
}
